class ATMController:
    def __init__(self):
        self.accounts = {}
        self.logged_in = False
        self.current_account = None

    def create_account(self, account_number, pin, balance=0):
        self.accounts[account_number] = {'pin': pin, 'balance': balance}

    def login(self, account_number, pin):
        if account_number in self.accounts and self.accounts[account_number]['pin'] == pin:
            self.logged_in = True
            self.current_account = account_number
            return True
        return False

    def logout(self):
        self.logged_in = False
        self.current_account = None

    def check_balance(self):
        if self.logged_in:
            return self.accounts[self.current_account]['balance']
        return None

    def withdraw(self, amount):
        if self.logged_in:
            if amount <= self.accounts[self.current_account]['balance']:
                self.accounts[self.current_account]['balance'] -= amount
                return True
            return False
        return None

    def deposit(self, amount):
        if self.logged_in:
            self.accounts[self.current_account]['balance'] += amount
            return True
        return None

    def transfer(self, recipient_account, amount):
        if self.logged_in:
            if recipient_account in self.accounts:
                if amount <= self.accounts[self.current_account]['balance']:
                    self.accounts[self.current_account]['balance'] -= amount
                    self.accounts[recipient_account]['balance'] += amount
                    return True
                return False
            return None
        return None

